from abc import ABC, abstractmethod

class Img(ABC):
    @abstractmethod
    def show(self): pass

class RealImg(Img):
    def __init__(self, f): self.f=f; self._load()
    def _load(self): print(f'{self.f} yukleniyor')
    def show(self): print(f'{self.f} gosteriliyor')

class Proxy(Img):
    def __init__(self, f): self.f=f; self.real=None
    def show(self):
        if not self.real: self.real=RealImg(self.f)
        self.real.show()

Proxy('foto.jpg').show()
```

