from abc import ABC, abstractmethod

class State(ABC):
    @abstractmethod
    def handle(self, ctx): pass

class Start(State):
    def handle(self, ctx):
        print('Basliyor'); ctx.state = Running()

class Running(State):
    def handle(self, ctx):
        print('Calisiyor'); ctx.state = Stop()

class Stop(State):
    def handle(self, ctx):
        print('Durdu'); ctx.state = Start()

class Ctx:
    def __init__(self): self.state = Start()
    def req(self): self.state.handle(self)

c = Ctx()
