function factorial(n) {
    if (n <= 1) return 1;
    return n * factorial(n - 1);
}

// 2. Iteratif cozum kullanin
function factorialIter(n) {
    let result = 1;
    for (let i = 2; i <= n; i++) {
        result *= i;
    }
