def infix_to_postfix(ifade):
    oncelik={'+':1,'-':1,'*':2,'/':2,'^':3}
    stack=[]; cikti=[]
    for token in ifade:
        if token.isdigit(): cikti.append(token)
        elif token in oncelik:
            while stack and stack[-1]!='(' and oncelik.get(stack[-1],0)>=oncelik[token]:
                cikti.append(stack.pop())
            stack.append(token)
        elif token=='(': stack.append(token)
        elif token==')':
            while stack and stack[-1]!='(': cikti.append(stack.pop())
            stack.pop()
    while stack: cikti.append(stack.pop())
    return ''.join(cikti)

print(infix_to_postfix('3+4*2'))
