    stack=[]
    for token in ifade:
        if token.isdigit(): stack.append(int(token))
        else:
            b=stack.pop(); a=stack.pop()
            if token=='+': stack.append(a+b)
            elif token=='-': stack.append(a-b)
            elif token=='*': stack.append(a*b)
