class FenwickTree:
    def __init__(self,n):
        self.n=n; self.bit=[0]*(n+1)
    def guncelle(self,idx,delta):
        i=idx+1
        while i<=self.n: self.bit[i]+=delta; i+=i&-i
    def prefix_toplam(self,idx):
        i=idx+1; t=0
        while i>0: t+=self.bit[i]; i-=i&-i
        return t
    def aralik_toplam(self,l,r):
        return self.prefix_toplam(r)-self.prefix_toplam(l-1)

