def ternary_search(arr,t,l,r):
    if r>=l:
        m1=l+(r-l)//3; m2=r-(r-l)//3
        if arr[m1]==t: return m1
        if arr[m2]==t: return m2
        if t<arr[m1]: return ternary_search(arr,t,l,m1-1)
        elif t>arr[m2]: return ternary_search(arr,t,m2+1,r)
        else: return ternary_search(arr,t,m1+1,m2-1)
