def bellman_ford(edges,V,bas):
    dist=[float('inf')]*V; dist[bas]=0
    for _ in range(V-1):
        for u,v,w in edges:
            if dist[u]!=float('inf') and dist[u]+w<dist[v]:
                dist[v]=dist[u]+w
    for u,v,w in edges:
        if dist[u]!=float('inf') and dist[u]+w<dist[v]:
