def floyd_warshall(graph):
    V=len(graph)
    dist=[[float('inf')]*V for _ in range(V)]
    for i in range(V):
        dist[i][i]=0
        for j,w in graph[i]: dist[i][j]=w
    for k in range(V):
        for i in range(V):
            for j in range(V):
                if dist[i][k]+dist[k][j]<dist[i][j]:
                    dist[i][j]=dist[i][k]+dist[k][j]
    return dist
