def kosaraju(graph,V):
    visited=[False]*V; stack=[]
    def dfs(u):
        visited[u]=True
        for v in graph[u]:
            if not visited[v]: dfs(v)
        stack.append(u)
    for i in range(V):
        if not visited[i]: dfs(i)
    rev=[[] for _ in range(V)]
    for u in range(V):
        for v in graph[u]: rev[v].append(u)
    visited=[False]*V; sccs=[]
    def dfs_rev(u,comp):
        visited[u]=True; comp.append(u)
        for v in rev[u]:
            if not visited[v]: dfs_rev(v,comp)
    while stack:
        u=stack.pop()
        if not visited[u]:
            comp=[]; dfs_rev(u,comp); sccs.append(comp)
    return sccs
