import heapq
def a_star(graph,heuristic,start,goal):
    open_set=[(heuristic[start],start)]
    g={start:0}
    while open_set:
        _,u=heapq.heappop(open_set)
        if u==goal: return g[u]
        for v,w in graph[u]:
            new_g=g[u]+w
            if new_g<g.get(v,float('inf')):
                g[v]=new_g
                heapq.heappush(open_set,(new_g+heuristic[v],v))
    return None

