            raise
    return wrapper

def logging(fonk):
    def wrapper(*args,**kwargs):
        print(f'{fonk.__name__} basladi')
        return fonk(*args,**kwargs)
    return wrapper

@logging
@transaction
def para_gonder(miktar):
    print(f'{miktar} TL gonderildi')

