import random
class LoadBalancer:
    def __init__(self):
        self.sunucular=['server1','server2','server3']
        self.index=0
    def round_robin(self):
        s=self.sunucular[self.index]
        self.index=(self.index+1)%len(self.sunucular)
        return s
    def random(self):
        return random.choice(self.sunucular)
    def least_connections(self,connections):
        return min(connections, key=connections.get)

