class DisjointSet:
    def __init__(self,n):
        self.parent=list(range(n))
        self.rank=[0]*n
    def find(self,x):
        if self.parent[x]!=x:
            self.parent[x]=self.find(self.parent[x])
        return self.parent[x]
    def union(self,x,y):
        rx,ry=self.find(x),self.find(y)
        if rx==ry: return False
        if self.rank[rx]<self.rank[ry]:
            self.parent[rx]=ry
        elif self.rank[rx]>self.rank[ry]:
            self.parent[ry]=rx
        else:
            self.parent[ry]=rx
            self.rank[rx]+=1
        return True
    def bagli_mi(self,x,y):
        return self.find(x)==self.find(y)

ds=DisjointSet(5)
ds.union(0,1); ds.union(2,3); ds.union(1,2)
print(ds.bagli_mi(0,3))  # True
print(ds.bagli_mi(0,4))  # False
