```python
# Greedy paraustu (her zaman en buyuk para)
def greedy_paraustu(coins,amount):
    coins.sort(reverse=True)
    result=[]
    for c in coins:
        while amount>=c:
            result.append(c); amount-=c
    return result

# DP paraustu (minimum sayi)
def dp_paraustu(coins,amount):
    dp=[float('inf')]*(amount+1); dp[0]=0
    for i in range(1,amount+1):
        for c in coins:
            if c<=i:
                dp[i]=min(dp[i],dp[i-c]+1)
    return dp[amount] if dp[amount]!=float('inf') else -1

coins=[1,5,10,25]
print(f'Greedy: {greedy_paraustu(coins,30)}')
print(f'DP: {dp_paraustu(coins,30)}')
