import time

class BuyukResim:
    def __init__(self,dosya):
        print(f'Resim yukleniyor: {dosya}')
        time.sleep(1)  # yavas yukleme
        self.dosya=dosya
        self.veri=f'{dosya} verisi'
    def goster(self):
        return f'Gosteriliyor: {self.veri}'

class ProxyResim:
    def __init__(self,dosya):
        self.dosya=dosya
        self.gercek_resim=None
    def goster(self):
        if not self.gercek_resim:
            self.gercek_resim=BuyukResim(self.dosya)
        return self.gercek_resim.goster()

# Proxy ile - sadece goster cagrilinca yuklenir
