class CircuitBreaker:
    def __init__(self,threshold=5):
        self.threshold=threshold
        self.hata_sayisi=0
        self.acik=False
    def cagri_yap(self,func):
        if self.acik:
            raise Exception('Circuit breaker ACIK')
        try:
            sonuc=func()
            self.hata_sayisi=0
            return sonuc
        except:
            self.hata_sayisi+=1
            if self.hata_sayisi>=self.threshold:
                self.acik=True
            raise

