def inorder_successor(root,val):
    successor=None
    while root:
        if val<root.val:
            successor=root
            root=root.left
        elif val>root.val:
            root=root.right
        else:
            if root.right:
                temp=root.right
                while temp.left: temp=temp.left
                return temp.val
            break
    return successor.val if successor else None
