Aralik guncellemelerini O(log n) yapar.

```python
class LazySegmentTree:
    def __init__(self,arr):
        self.n=len(arr);self.tree=[0]*(4*self.n);self.lazy=[0]*(4*self.n)
    def guncelle(self,l,r,val):
        self._guncelle(0,0,self.n-1,l,r,val)
    def _guncelle(self,node,bas,son,l,r,val):
        if self.lazy[node]:
            self.tree[node]+=(son-bas+1)*self.lazy[node]
            if bas!=son:
                self.lazy[2*node+1]+=self.lazy[node]
                self.lazy[2*node+2]+=self.lazy[node]
            self.lazy[node]=0
        if son<l or bas>r: return
        if l<=bas and son<=r:
            self.tree[node]+=(son-bas+1)*val
            if bas!=son:
                self.lazy[2*node+1]+=val;self.lazy[2*node+2]+=val
            return
        orta=(bas+son)//2
        self._guncelle(2*node+1,bas,orta,l,r,val)
        self._guncelle(2*node+2,orta+1,son,l,r,val)
        self.tree[node]=self.tree[2*node+1]+self.tree[2*node+2]
```

