def seviyeleri_bul(grafik,bas):
    from collections import deque
    visited={bas}
    q=deque([(bas,0)])
    seviyeler={}
    while q:
        u,seviye=q.popleft()
        seviyeler.setdefault(seviye,[]).append(u)
        for v in grafik[u]:
            if v not in visited:
                visited.add(v);q.append((v,seviye+1))
    return seviyeler

