    if not root: return AVLNode(val)
    if val<root.val: root.left=avl_ekle(root.left,val)
    else: root.right=avl_ekle(root.right,val)

    root.yuk=1+max(yuk(root.left),yuk(root.right))
    dg=denge(root)

